  1	import React, { FC, FormEvent } from 'react';
  2	import { ensurePath } from 'src/utils/helpers';
  3	import { useNMStateTranslation } from 'src/utils/hooks/useNMStateTranslation';
  4	
  5	import { Button, FormGroup, Grid, GridItem, TextInput } from '@patternfly/react-core';
  6	import { MinusCircleIcon, PlusCircleIcon } from '@patternfly/react-icons';
  7	import { NodeNetworkConfigurationInterface } from '@types';
  8	
  9	import { BOND_OPTIONS_KEYS } from './constants';
 10	
 11	type BondOptionsProps = {
 12	  id: number;
 13	  policyInterface?: NodeNetworkConfigurationInterface;
 14	  onInterfaceChange?: (
 15	    updateInterface: (policyInterface: NodeNetworkConfigurationInterface) => void,
 16	  ) => void;
 17	};
 18	
 19	const BondOptions: FC<BondOptionsProps> = ({ id, onInterfaceChange, policyInterface }) => {
 20	  const { t } = useNMStateTranslation();
 21	  const options = policyInterface?.['link-aggregation']?.options || {};
 22	
 23	  const selectableOptions = BOND_OPTIONS_KEYS.filter((optionKey) => !(optionKey in options));
 24	
 25	  const onKeyChange = (oldKey, newKey) => {
 26	    onInterfaceChange((draftInterface) => {
 27	      ensurePath(draftInterface, 'link-aggregation.options');
 28	      draftInterface['link-aggregation'].options[newKey] =
 29	        draftInterface['link-aggregation'].options[oldKey];
 30	      delete draftInterface['link-aggregation'].options[oldKey];
 31	    });
 32	  };
 33	
 34	  const onOptionValue = (key, value) => {
 35	    onInterfaceChange((draftInterface) => {
 36	      ensurePath(draftInterface, 'link-aggregation.options');
 37	      draftInterface['link-aggregation'].options[key] = value;
 38	    });
 39	  };
 40	
 41	  const onDelete = (key) => {
 42	    onInterfaceChange((draftInterface) => {
 43	      ensurePath(draftInterface, 'link-aggregation.options');
 44	      delete draftInterface['link-aggregation'].options[key];
 45	    });
 46	  };
 47	
 48	  const onOptionAdd = () => {
 49	    onInterfaceChange((draftInterface) => {
 50	      ensurePath(draftInterface, 'link-aggregation.options');
 51	      draftInterface['link-aggregation'].options[selectableOptions[0]] = '';
 52	    });
 53	  };
 54	
 55	  return (
 56	    <>
 57	      {Object.entries(options).map(([key, value], index) => (
 58	        <Grid key={index}>
 59	          <GridItem span={5}>
 60	            <FormGroup label={t('Key')} fieldId={`label-${id}-key-input`}>
 61	              <TextInput
 62	                id={`label-${id}-key-input`}
 63	                placeholder={t('Key')}
 64	                isRequired
 65	                type="text"
 66	                value={key}
 67	                onChange={(event: FormEvent<HTMLInputElement>, newKey: string) =>
 68	                  onKeyChange(key, newKey)
 69	                }
 70	                aria-label={t('selector key')}
 71	              />
 72	            </FormGroup>
 73	          </GridItem>
 74	          <GridItem span={1} />
 75	          <GridItem span={5}>
 76	            <FormGroup label={t('Value')} fieldId={`label-${id}-value-input`}>
 77	              <TextInput
 78	                id={`label-${id}-value-input`}
 79	                placeholder={t('Value')}
 80	                isRequired
 81	                type="text"
 82	                value={value}
 83	                onChange={(event: FormEvent<HTMLInputElement>, newValue: string) =>
 84	                  onOptionValue(key, newValue)
 85	                }
 86	                aria-label={t('selector value')}
 87	              />
 88	            </FormGroup>
 89	          </GridItem>
 90	
 91	          <GridItem span={1}>
 92	            <FormGroup label=" " fieldId={`label-${id}-delete-btn`}>
 93	              <Button variant="plain" onClick={() => onDelete(key)}>
 94	                <MinusCircleIcon />
 95	              </Button>
 96	            </FormGroup>
 97	          </GridItem>
 98	        </Grid>
 99	      ))}
100	
101	      {selectableOptions.length > 0 && (
102	        <Button
103	          className="pf-m-link-align-left pf-m-text-align-left"
104	          id="add-option-button"
105	          variant="link"
106	          onClick={() => onOptionAdd()}
107	          icon={<PlusCircleIcon />}
108	        >
109	          {t('Add Option')}
110	        </Button>
111	      )}
112	    </>
113	  );
114	};
115	
116	export default BondOptions;

